import sys

def solve_case(r, c, grid, queries):
    # your code here — return a list with one answer per query
    return [0] * len(queries)

def main():
    data = sys.stdin.read().split()
    pos = 0
    t = int(data[pos]); pos += 1
    out = []
    for _ in range(t):
        r, c, q = int(data[pos]), int(data[pos + 1]), int(data[pos + 2]); pos += 3
        grid = []
        for _ in range(r):
            grid.append([int(x) for x in data[pos:pos + c]]); pos += c
        queries = []
        for _ in range(q):
            queries.append((int(data[pos]), int(data[pos + 1]), int(data[pos + 2]), int(data[pos + 3]))); pos += 4
        out.extend(str(ans) for ans in solve_case(r, c, grid, queries))
    sys.stdout.write("\n".join(out) + "\n")

main()

