import java.io.*;
import java.util.*;

public class Main {
    static long[] solveCase(int r, int c, int[][] grid, int[][] queries) {
        // your code here — return one answer per query
        return new long[queries.length];
    }

    public static void main(String[] args) throws IOException {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StreamTokenizer in = new StreamTokenizer(br);
        in.nextToken();
        int t = (int) in.nval;
        StringBuilder out = new StringBuilder();
        while (t-- > 0) {
            in.nextToken(); int r = (int) in.nval;
            in.nextToken(); int c = (int) in.nval;
            in.nextToken(); int q = (int) in.nval;
            int[][] grid = new int[r][c];
            for (int i = 0; i < r; i++)
                for (int j = 0; j < c; j++) { in.nextToken(); grid[i][j] = (int) in.nval; }
            int[][] queries = new int[q][4];
            for (int i = 0; i < q; i++)
                for (int j = 0; j < 4; j++) { in.nextToken(); queries[i][j] = (int) in.nval; }
            for (long ans : solveCase(r, c, grid, queries)) out.append(ans).append('\n');
        }
        System.out.print(out);
    }
}

