int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int t;
    cin >> t;
    while (t--) {
        int r, c, q;
        cin >> r >> c >> q;
        vector<vector<int>> grid(r, vector<int>(c));
        for (auto& row : grid)
            for (auto& x : row) cin >> x;
        vector<array<int, 4>> queries(q);
        for (auto& qu : queries) cin >> qu[0] >> qu[1] >> qu[2] >> qu[3];
        for (long long ans : solve_case(r, c, grid, queries)) cout << ans << '\n';
    }
    return 0;
}

